import React, { useState } from "react";

export default function ComplaintPage() {
  const [activeTab, setActiveTab] = useState("new");
  const [category, setCategory] = useState("");
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [errors, setErrors] = useState({});
  const [complaints, setComplaints] = useState([
    {
      id: "CMP-001",
      title: "WiFi issue in Block B",
      category: "IT / WiFi",
      status: "In Progress",
      date: "Mar 28, 2024",
    },
    {
      id: "CMP-002",
      title: "Mess food quality",
      category: "Canteen / Food",
      status: "Resolved",
      date: "Mar 20, 2024",
    },
  ]);

  const categories = [
    "Hostel & Accommodation",
    "Academic",
    "Canteen / Food",
    "Transport",
    "Infrastructure",
    "IT / Wi-Fi",
    "Other",
  ];

  const handleSubmit = () => {
    const newErrors = {};
    if (!category) newErrors.category = "Please select a category";
    if (!title || title.length < 5) newErrors.title = "Title must be at least 5 characters";
    if (!description || description.length < 10)
      newErrors.description = "Description must be at least 10 characters";

    if (Object.keys(newErrors).length > 0) {
      setErrors(newErrors);
      return;
    }

    const newComplaint = {
      id: `CMP-${String(complaints.length + 1).padStart(3, "0")}`,
      title,
      category,
      status: "Open",
      date: new Date().toLocaleDateString("en-US", {
        year: "numeric",
        month: "short",
        day: "numeric",
      }),
    };

    setComplaints([newComplaint, ...complaints]);
    setCategory("");
    setTitle("");
    setDescription("");
    setErrors({});
    setActiveTab("track");
  };

  return (
    <div className="space-y-8">
      {/* Header */}
      <div className="glass-card p-8 space-y-2">
        <h1 className="text-3xl font-bold text-slate-900">📋 Complaints</h1>
        <p className="text-slate-600">Submit and track your complaints</p>
      </div>

      {/* Tabs */}
      <div className="glass-card p-4 flex gap-4">
        <button
          onClick={() => setActiveTab("new")}
          className={`px-6 py-3 rounded-lg font-semibold transition-all ${
            activeTab === "new"
              ? "tab-active bg-blue-100 text-blue-700"
              : "tab-inactive hover:bg-slate-100"
          }`}
        >
          ➕ New Complaint
        </button>
        <button
          onClick={() => setActiveTab("track")}
          className={`px-6 py-3 rounded-lg font-semibold transition-all ${
            activeTab === "track"
              ? "tab-active bg-blue-100 text-blue-700"
              : "tab-inactive hover:bg-slate-100"
          }`}
        >
          📝 My Complaints ({complaints.length})
        </button>
      </div>

      {/* New Complaint Tab */}
      {activeTab === "new" && (
        <div className="glass-card p-8 space-y-6 max-w-2xl">
          <h2 className="text-2xl font-bold text-slate-900">File a Complaint</h2>

          {/* Category */}
          <div className="space-y-2">
            <label className="block font-semibold text-slate-700">Category *</label>
            <select
              value={category}
              onChange={(e) => {
                setCategory(e.target.value);
                setErrors((prev) => ({ ...prev, category: null }));
              }}
              className={`w-full px-4 py-3 rounded-lg border bg-white/70 focus:outline-none focus:ring-2 focus:ring-blue-200 transition-all ${
                errors.category ? "border-red-500" : "border-slate-300"
              }`}
            >
              <option value="">Select a category...</option>
              {categories.map((cat) => (
                <option key={cat} value={cat}>
                  {cat}
                </option>
              ))}
            </select>
            {errors.category && <p className="text-sm text-red-600">{errors.category}</p>}
          </div>

          {/* Title */}
          <div className="space-y-2">
            <label className="block font-semibold text-slate-700">Title *</label>
            <input
              type="text"
              placeholder="Brief title of the issue"
              value={title}
              onChange={(e) => {
                setTitle(e.target.value);
                setErrors((prev) => ({ ...prev, title: null }));
              }}
              className={`w-full px-4 py-3 rounded-lg border bg-white/70 focus:outline-none focus:ring-2 focus:ring-blue-200 transition-all ${
                errors.title ? "border-red-500" : "border-slate-300"
              }`}
            />
            {errors.title && <p className="text-sm text-red-600">{errors.title}</p>}
          </div>

          {/* Description */}
          <div className="space-y-2">
            <label className="block font-semibold text-slate-700">Description *</label>
            <textarea
              placeholder="Describe the issue in detail..."
              value={description}
              onChange={(e) => {
                setDescription(e.target.value);
                setErrors((prev) => ({ ...prev, description: null }));
              }}
              rows="5"
              className={`w-full px-4 py-3 rounded-lg border bg-white/70 focus:outline-none focus:ring-2 focus:ring-blue-200 transition-all resize-none ${
                errors.description ? "border-red-500" : "border-slate-300"
              }`}
            />
            {errors.description && (
              <p className="text-sm text-red-600">{errors.description}</p>
            )}
          </div>

          {/* Submit Button */}
          <button onClick={handleSubmit} className="btn-primary w-full py-3">
            Submit Complaint
          </button>
        </div>
      )}

      {/* Track Complaints Tab */}
      {activeTab === "track" && (
        <div className="space-y-4">
          {complaints.length === 0 ? (
            <div className="glass-card p-8 text-center space-y-3">
              <p className="text-2xl">📪</p>
              <p className="text-slate-600">No complaints yet</p>
            </div>
          ) : (
            complaints.map((complaint) => (
              <div key={complaint.id} className="glass-card p-6 space-y-3">
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <p className="font-mono text-sm text-blue-600">{complaint.id}</p>
                    <p className="text-xl font-bold text-slate-900">{complaint.title}</p>
                    <p className="text-sm text-slate-600 mt-1">{complaint.category}</p>
                  </div>
                  <span
                    className={`px-4 py-2 rounded-full font-semibold text-sm whitespace-nowrap ml-4 ${
                      complaint.status === "Resolved"
                        ? "bg-emerald-100 text-emerald-700"
                        : complaint.status === "In Progress"
                        ? "bg-amber-100 text-amber-700"
                        : "bg-blue-100 text-blue-700"
                    }`}
                  >
                    {complaint.status}
                  </span>
                </div>

                <div className="flex items-center justify-between pt-2 border-t border-slate-200">
                  <span className="text-xs text-slate-500">📅 {complaint.date}</span>
                  <button className="text-sm font-semibold text-blue-600 hover:text-blue-700">
                    View Details →
                  </button>
                </div>
              </div>
            ))
          )}
        </div>
      )}
    </div>
  );
}
